(function(){var carousels=document.querySelectorAll("[data-labs-carousel]");if(!carousels.length){return}carousels.forEach(function(carousel){var viewport=carousel.querySelector(".home-labs-stories__viewport");var track=carousel.querySelector("[data-labs-track]");var prev=carousel.querySelector("[data-labs-prev]");var next=carousel.querySelector("[data-labs-next]");var originals=track?Array.from(track.children):[];if(!viewport||!track||originals.length<2){return}var delay=parseInt(carousel.getAttribute("data-labs-delay")||"2000",10);var perView=5;var index=0;var itemWidth=0;var timer=null;var clonesBefore=[];var clonesAfter=[];var setup=function(){clonesBefore.forEach(function(node){node.remove()});clonesAfter.forEach(function(node){node.remove()});clonesBefore=[];clonesAfter=[];perView=Math.min(5,originals.length);for(var i=originals.length-perView;i<originals.length;i+=1){var beforeClone=originals[i].cloneNode(true);beforeClone.setAttribute("aria-hidden","true");beforeClone.tabIndex=-1;track.insertBefore(beforeClone,track.firstChild);clonesBefore.push(beforeClone)}for(var j=0;j<perView;j+=1){var afterClone=originals[j].cloneNode(true);afterClone.setAttribute("aria-hidden","true");afterClone.tabIndex=-1;track.appendChild(afterClone);clonesAfter.push(afterClone)}itemWidth=originals[0].getBoundingClientRect().width+(parseFloat(getComputedStyle(track).gap)||0);index=perView;track.style.transition="none";track.style.transform="translateX("+(-index*itemWidth)+"px)"};var jumpIfNeeded=function(){if(index>=originals.length+perView){index=perView;track.style.transition="none";track.style.transform="translateX("+(-index*itemWidth)+"px)"}else if(index<perView){index=originals.length+perView-1;track.style.transition="none";track.style.transform="translateX("+(-index*itemWidth)+"px)"}};var goTo=function(newIndex){index=newIndex;track.style.transition="transform .45s ease";track.style.transform="translateX("+(-index*itemWidth)+"px)"};var nextSlide=function(){goTo(index+1)};var prevSlide=function(){goTo(index-1)};var start=function(){stop();timer=window.setInterval(nextSlide,delay)};var stop=function(){if(timer){window.clearInterval(timer);timer=null}};track.addEventListener("transitionend",jumpIfNeeded);next&&next.addEventListener("click",function(){nextSlide();start()});prev&&prev.addEventListener("click",function(){prevSlide();start()});carousel.addEventListener("mouseenter",stop);carousel.addEventListener("mouseleave",start);window.addEventListener("resize",function(){setup();start()});setup();start()})})();
